request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?mis ?misName ?slot ?val ?unit ?type WHERE {
  ?req rdf:type vocab:tmt%20requirement .
  ?req vocab:NamedElement_name ?reqName .
  FILTER(
    CONTAINS(LCASE(STR(?reqName)), LCASE("misalign")) ||
    CONTAINS(LCASE(STR(?reqName)), LCASE("offload")) ||
    CONTAINS(LCASE(STR(?reqName)), LCASE("offset"))
  )

  ?req vocab:Element_ownedElement+ ?mis .
  ?mis vocab:NamedElement_name ?misName .

  OPTIONAL {
    ?mis rdf:type ?type .
  }

  OPTIONAL {
    ?mis vocab:element%20value ?val .
  }
  OPTIONAL {
    ?mis vocab:Slot_value ?val .
  }
  OPTIONAL {
    ?slot rdf:type vocab:Slot .
    ?slot vocab:Slot_value ?val .
  }
  OPTIONAL {
    ?mis vocab:NamedElement_name ?unit .
  }

  FILTER(
    CONTAINS(LCASE(STR(?misName)), LCASE("m1")) ||
    CONTAINS(LCASE(STR(?misName)), LCASE("misalign")) ||
    CONTAINS(LCASE(STR(?misName)), LCASE("offset"))
  )
}
LIMIT 25
